// Build a clean client record from the inbound payload
const body = $input.first().json.body;

const clientId = 'client_' + Date.now();

const TIER_PRODUCTS = {
  starter: ['P07', 'P01'],
  growth:  ['P07', 'P01', 'P03', 'P04', 'P02'],
  scale:   ['P07', 'P01', 'P03', 'P04', 'P02', 'P05', 'P06', 'P08']
};

const TIER_PRICES = {
  starter: { mrr: 99,  setup: 299 },
  growth:  { mrr: 249, setup: 499 },
  scale:   { mrr: 499, setup: 999 }
};

const tier = body.tier || 'starter';

return [{
  json: {
    clientId,
    tier,
    mrr: TIER_PRICES[tier].mrr,
    setup: TIER_PRICES[tier].setup,
    products: TIER_PRODUCTS[tier],
    firstName: body.client.firstName,
    lastName:  body.client.lastName,
    email:     body.client.email,
    company:   body.client.company,
    industry:  body.client.industry  || '',
    teamSize:  body.client.teamSize  || '',
    credentials: body.credentials   || {},
    receivedAt: new Date().toISOString()
  }
}];

// Build n8n credential objects for each credential the client provided
// Uses the n8n REST API to create them programmatically

const client = $('Code — Parse & Enrich Payload').first().json;
const creds   = client.credentials;
const id      = client.clientId;

// Map credential keys → n8n credential type + data shape
const CRED_MAP = {
  google_oauth_token: {
    type: 'googleOAuth2Api',
    name: `${id} — Google OAuth2`,
    data: { accessToken: creds.google_oauth_token }
  },
  openai_api_key: {
    type: 'openAiApi',
    name: `${id} — OpenAI`,
    data: { apiKey: creds.openai_api_key }
  },
  zoom_client_id: {
    type: 'zoomOAuth2Api',
    name: `${id} — Zoom OAuth2`,
    data: { clientId: creds.zoom_client_id, clientSecret: creds.zoom_client_secret }
  },
  hubspot_api_key: {
    type: 'hubspotApi',
    name: `${id} — HubSpot`,
    data: { apiKey: creds.hubspot_api_key }
  },
  airtable_token: {
    type: 'airtableTokenApi',
    name: `${id} — Airtable`,
    data: { accessToken: creds.airtable_token }
  },
  blotato_api_key: {
    type: 'httpHeaderAuth',
    name: `${id} — Blotato`,
    data: { name: 'Authorization', value: `Bearer ${creds.blotato_api_key}` }
  },
  wordpress_app_password: {
    type: 'httpBasicAuth',
    name: `${id} — WordPress`,
    data: { user: creds.wordpress_username || 'admin', password: creds.wordpress_app_password }
  },
  perplexity_api_key: {
    type: 'httpHeaderAuth',
    name: `${id} — Perplexity`,
    data: { name: 'Authorization', value: `Bearer ${creds.perplexity_api_key}` }
  },
  qdrant_api_key: {
    type: 'httpHeaderAuth',
    name: `${id} — Qdrant`,
    data: { name: 'api-key', value: creds.qdrant_api_key }
  },
  meta_system_token: {
    type: 'httpHeaderAuth',
    name: `${id} — Meta`,
    data: { name: 'Authorization', value: `Bearer ${creds.meta_system_token}` }
  },
  calendly_api_key: {
    type: 'httpHeaderAuth',
    name: `${id} — Calendly`,
    data: { name: 'Authorization', value: `Bearer ${creds.calendly_api_key}` }
  }
};

// Only build credentials that the client actually provided
const toCreate = Object.entries(CRED_MAP)
  .filter(([key]) => creds[key] && creds[key].trim() !== '')
  .map(([, val]) => ({ json: val }));

return toCreate.length > 0 ? toCreate : [{ json: { skipped: true } }];

// Collect all created credential IDs and map them back to type
// so downstream workflow-activation nodes can reference them

const items = $input.all();
const credMap = {};

for (const item of items) {
  if (item.json.id && item.json.type) {
    credMap[item.json.type] = item.json.id;
  }
}

const client = $('Code — Parse & Enrich Payload').first().json;

return [{ json: { ...client, credentialIds: credMap } }];

// For each product in the client's tier, find the template workflow
// and build the activation payload

const client = $input.first().json;

// Template workflow IDs — replace with actual IDs from your n8n instance
// Find these at: GET /api/v1/workflows
const WORKFLOW_TEMPLATES = {
  P07: '{{TEMPLATE_WORKFLOW_ID_P07}}',
  P01: '{{TEMPLATE_WORKFLOW_ID_P01}}',
  P03: '{{TEMPLATE_WORKFLOW_ID_P03}}',
  P04: '{{TEMPLATE_WORKFLOW_ID_P04}}',
  P02: '{{TEMPLATE_WORKFLOW_ID_P02}}',
  P05: '{{TEMPLATE_WORKFLOW_ID_P05}}',
  P06: '{{TEMPLATE_WORKFLOW_ID_P06}}',
  P08: '{{TEMPLATE_WORKFLOW_ID_P08}}'
};

const activations = client.products.map(pid => ({
  json: {
    clientId:   client.clientId,
    productId:  pid,
    templateId: WORKFLOW_TEMPLATES[pid],
    credentialIds: client.credentialIds,
    clientEmail: client.email,
    company: client.company
  }
}));

return activations;

// Duplicate the template workflow for this client:
// 1. Rename it with client ID
// 2. Swap credential IDs in all nodes
// 3. Replace {{CLIENT_ID}} placeholders in webhook paths

const item = $input.first().json;
const template = item;  // full workflow object from n8n API
const meta = $('Code — Prepare Workflow Activations').first().json;

// Deep clone and rename
const clientWorkflow = JSON.parse(JSON.stringify(template));
clientWorkflow.name = `[${meta.clientId}] ${template.name}`;
delete clientWorkflow.id;  // remove so n8n creates a new one
clientWorkflow.active = true;

// Credential type → ID mapping from what we created
const credIds = meta.credentialIds;
const TYPE_MAP = {
  googleOAuth2Api:   credIds['googleOAuth2Api'],
  openAiApi:         credIds['openAiApi'],
  zoomOAuth2Api:     credIds['zoomOAuth2Api'],
  hubspotApi:        credIds['hubspotApi'],
  airtableTokenApi:  credIds['airtableTokenApi'],
  httpHeaderAuth:    credIds['httpHeaderAuth'],
  httpBasicAuth:     credIds['httpBasicAuth']
};

// Walk all nodes and swap credential IDs
if (clientWorkflow.nodes) {
  clientWorkflow.nodes = clientWorkflow.nodes.map(node => {
    if (node.credentials) {
      for (const [credType, credObj] of Object.entries(node.credentials)) {
        if (TYPE_MAP[credType]) {
          node.credentials[credType] = {
            id: TYPE_MAP[credType],
            name: node.credentials[credType].name
          };
        }
      }
    }
    // Replace CLIENT_ID placeholders in webhook paths and HTTP URLs
    if (node.parameters) {
      const paramStr = JSON.stringify(node.parameters)
        .replace(/\{\{CLIENT_ID\}\}/g, meta.clientId)
        .replace(/\{\{CLIENT_EMAIL\}\}/g, meta.clientEmail);
      node.parameters = JSON.parse(paramStr);
    }
    return node;
  });
}

return [{ json: { workflow: clientWorkflow, clientId: meta.clientId, productId: meta.productId } }];

